CREATE TYPE "crm_company_type" AS ENUM ('client', 'vendor', 'network', 'studio', 'production_company');
CREATE TABLE "crm_companies" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "organization_id" uuid NOT NULL REFERENCES "organizations"("id") ON DELETE cascade, "name" text NOT NULL, "type" "crm_company_type" NOT NULL, "payment_terms_days" integer, "billing_email" text, "address" text, "notes" text, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE UNIQUE INDEX "crm_companies_org_name_idx" ON "crm_companies" ("organization_id", "name");
CREATE TABLE "crm_contacts" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "organization_id" uuid NOT NULL REFERENCES "organizations"("id") ON DELETE cascade, "company_id" uuid NOT NULL REFERENCES "crm_companies"("id") ON DELETE cascade, "name" text NOT NULL, "title" text, "email" text, "phone" text, "is_primary" boolean DEFAULT false NOT NULL, "notes" text, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE "show_contacts" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "organization_id" uuid NOT NULL REFERENCES "organizations"("id") ON DELETE cascade, "show_id" uuid NOT NULL REFERENCES "shows"("id") ON DELETE cascade, "contact_id" uuid NOT NULL REFERENCES "crm_contacts"("id") ON DELETE cascade, "relationship" text NOT NULL, "is_approval_contact" boolean DEFAULT false NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE "purchase_orders" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "organization_id" uuid NOT NULL REFERENCES "organizations"("id") ON DELETE cascade, "company_id" uuid NOT NULL REFERENCES "crm_companies"("id") ON DELETE restrict, "show_id" uuid REFERENCES "shows"("id") ON DELETE set null, "po_number" text NOT NULL, "amount" numeric(12,2), "currency" text DEFAULT 'GBP' NOT NULL, "status" text DEFAULT 'open' NOT NULL, "notes" text, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE UNIQUE INDEX "purchase_orders_org_number_idx" ON "purchase_orders" ("organization_id", "po_number");
